import React, { useState, useMemo } from 'react';

export default function DataTable({ columns, rows }) {
  const [query, setQuery] = useState('');
  const [sort, setSort] = useState({ key: null, dir: 'asc' });

  const view = useMemo(() => {
    const q = query.trim().toLowerCase();
    let r = rows.filter((row) => Object.values(row).join(' ').toLowerCase().includes(q));
    if (sort.key) {
      r = [...r].sort((a, b) => {
        const x = a[sort.key];
        const y = b[sort.key];
        const cmp = x > y ? 1 : x < y ? -1 : 0;
        return cmp * (sort.dir === 'asc' ? 1 : -1);
      });
    }
    return r;
  }, [rows, query, sort]);

  const toggleSort = (key) =>
    setSort((s) => (s.key !== key ? { key, dir: 'asc' } : { key, dir: s.dir === 'asc' ? 'desc' : 'asc' }));

  const th = { textAlign: 'left', padding: '8px 12px', borderBottom: '2px solid #e5e7eb', cursor: 'pointer', userSelect: 'none' };
  const td = { padding: '8px 12px', borderBottom: '1px solid #f1f5f9' };

  return (
    <div style={{ maxWidth: 460 }}>
      <input
        value={query}
        onChange={(e) => setQuery(e.target.value)}
        placeholder="Filter…"
        style={{ padding: 8, marginBottom: 10, width: '100%', boxSizing: 'border-box' }}
      />
      <table style={{ borderCollapse: 'collapse', width: '100%' }}>
        <thead>
          <tr>
            {columns.map((col) => (
              <th key={col.key} style={th} onClick={() => toggleSort(col.key)}>
                {col.label}
                {sort.key === col.key ? (sort.dir === 'asc' ? ' ▲' : ' ▼') : ''}
              </th>
            ))}
          </tr>
        </thead>
        <tbody>
          {view.map((row, i) => (
            <tr key={i}>
              {columns.map((col) => (
                <td key={col.key} style={td}>{row[col.key]}</td>
              ))}
            </tr>
          ))}
          {view.length === 0 && (
            <tr>
              <td colSpan={columns.length} style={{ ...td, color: '#9ca3af' }}>No matching rows</td>
            </tr>
          )}
        </tbody>
      </table>
    </div>
  );
}

