import { Component, Input } from '@angular/core';
import { NgModule } from '@angular/core';
import { BrowserModule } from '@angular/platform-browser';

interface Column { key: string; label: string; }

@Component({
  selector: 'app-data-table',
  template: `
    <div style="max-width: 460px;">
      <input [value]="query" (input)="query = $any($event.target).value" placeholder="Filter…" style="padding: 8px; margin-bottom: 10px; width: 100%; box-sizing: border-box;" />
      <table style="border-collapse: collapse; width: 100%;">
        <thead>
          <tr>
            <th
              *ngFor="let col of columns"
              (click)="toggleSort(col.key)"
              style="text-align: left; padding: 8px 12px; border-bottom: 2px solid #e5e7eb; cursor: pointer; user-select: none;"
            >
              {{ col.label }}<span *ngIf="sortKey === col.key">{{ sortDir === 'asc' ? ' ▲' : ' ▼' }}</span>
            </th>
          </tr>
        </thead>
        <tbody>
          <tr *ngFor="let row of view">
            <td *ngFor="let col of columns" style="padding: 8px 12px; border-bottom: 1px solid #f1f5f9;">{{ row[col.key] }}</td>
          </tr>
          <tr *ngIf="view.length === 0">
            <td [attr.colspan]="columns.length" style="padding: 8px 12px; color: #9ca3af;">No matching rows</td>
          </tr>
        </tbody>
      </table>
    </div>
  `,
})
export class DataTableComponent {
  @Input() columns: Column[] = [];
  @Input() rows: Record<string, any>[] = [];
  query = '';
  sortKey: string | null = null;
  sortDir: 'asc' | 'desc' = 'asc';

  get view(): Record<string, any>[] {
    const q = this.query.trim().toLowerCase();
    let r = this.rows.filter((row) => Object.values(row).join(' ').toLowerCase().indexOf(q) !== -1);
    if (this.sortKey) {
      const key = this.sortKey;
      const factor = this.sortDir === 'asc' ? 1 : -1;
      r = [...r].sort((a, b) => {
        const cmp = a[key] > b[key] ? 1 : a[key] < b[key] ? -1 : 0;
        return cmp * factor;
      });
    }
    return r;
  }

  toggleSort(key: string): void {
    if (this.sortKey !== key) {
      this.sortKey = key;
      this.sortDir = 'asc';
    } else {
      this.sortDir = this.sortDir === 'asc' ? 'desc' : 'asc';
    }
  }
}

@Component({
  selector: 'app-root',
  template: `
    <div style="font-family: sans-serif; padding: 20px;">
      <h1>Data Table Demo</h1>
      <app-data-table [columns]="columns" [rows]="rows"></app-data-table>
    </div>
  `,
})
export class AppComponent {
  columns: Column[] = [
    { key: 'name', label: 'Name' },
    { key: 'role', label: 'Role' },
    { key: 'age', label: 'Age' },
  ];
  rows = [
    { name: 'Ada', role: 'Engineer', age: 36 },
    { name: 'Grace', role: 'Admiral', age: 45 },
    { name: 'Linus', role: 'Maintainer', age: 29 },
    { name: 'Margaret', role: 'Director', age: 41 },
    { name: 'Dennis', role: 'Researcher', age: 33 },
  ];
}

@NgModule({
  declarations: [AppComponent, DataTableComponent],
  imports: [BrowserModule],
  bootstrap: [AppComponent],
})
export class AppModule {}
